import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'dart:convert';

class PaymentProcessor {
  final String apiKey;
  final String apiUrl;

  PaymentProcessor({required this.apiKey, required this.apiUrl});

  Future<void> processInAppPurchase(String productId) async {
    final response = await http.post(
      Uri.parse('$apiUrl/process_payment'),
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer $apiKey',
      },
      body: jsonEncode({
        'product_id': productId,
        'payment_method': 'in_app_purchase',
      }),
    );

    if (response.statusCode != 200) {
      throw Exception('Failed to process payment');
    }
  }

  Future<void> integrateWithMobileWallet(String walletId, double amount) async {
    final response = await http.post(
      Uri.parse('$apiUrl/process_payment'),
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer $apiKey',
      },
      body: jsonEncode({
        'wallet_id': walletId,
        'amount': amount,
        'payment_method': 'mobile_wallet',
      }),
    );

    if (response.statusCode != 200) {
      throw Exception('Failed to process payment');
    }
  }

  Future<void> handleTransaction(String transactionId, String status) async {
    final response = await http.post(
      Uri.parse('$apiUrl/update_transaction'),
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer $apiKey',
      },
      body: jsonEncode({
        'transaction_id': transactionId,
        'status': status,
      }),
    );

    if (response.statusCode != 200) {
      throw Exception('Failed to update transaction');
    }
  }
}

